   372→          RELEASE_ASSERT(false, fmt::format("Double registration for type: '{}' by '{}' and '{}'",
   373→                                            config_type, factory->name(),
   374→                                            it->second ? it->second->name() : ""));
   375→          it->second = nullptr;
   376→        } else {
   377→          mapping->emplace(std::make_pair(config_type, factory));
   378→        }
   379→      }
   380→    }
   381→
   382→    return mapping;
   383→  }
   384→
   385→  // Rebuild the factories-by-type map based on the current factories.
   386→  static void rebuildFactoriesByTypeForTest() {
   387→    auto& mapping = factoriesByType();
   388→    auto updated_mapping = buildFactoriesByType();
   389→
   390→    // Copy the updated mapping over the old one.
   391→    mapping = *updated_mapping;
   392→  }
   393→
   394→  /**
   395→   * Replaces a factory by name. This method should only be used for testing purposes.
   396→   * @param factory is the factory to inject.
   397→   * @param deprecated_names install the given deprecated names for this factory.
   398→   * @return std::function<void()> a function that will restore the previously registered factories
   399→   *         (by name or type).
   400→   */
   401→  static std::function<void()>
   402→  replaceFactoryForTest(Base& factory,
   403→                        std::initializer_list<absl::string_view> deprecated_names = {}) {
   404→    using DeprecatedNamesVector = std::vector<std::pair<std::string, std::string>>;
   405→
   406→    // If an existing factory is registered with this name, track it for later restoration.
   407→    Base* prev_by_name = nullptr;
   408→    auto it = factories().find(factory.name());
   409→    if (it != factories().end()) {
   410→      prev_by_name = it->second;
   411→      factories().erase(it);
   412→
   413→      ENVOY_LOG(
   414→          info, "Factory '{}' (type '{}') displaced-by-name with test factory '{}' (type '{}')",
   415→          prev_by_name->name(), prev_by_name->configTypes(), factory.name(), factory.configTypes());
   416→    } else {
   417→      ENVOY_LOG(info, "Factory '{}' (type '{}') registered for tests", factory.name(),
   418→                factory.configTypes());
   419→    }
   420→
   421→    factories().emplace(factory.name(), &factory);
   422→    RELEASE_ASSERT(getFactory(factory.name()) == &factory,
   423→                   "test factory by-name registration failed");
   424→
   425→    DeprecatedNamesVector prev_deprecated_names;
   426→    if (deprecated_names.size() > 0) {
   427→      for (auto deprecated_name : deprecated_names) {
   428→        auto it = deprecatedFactoryNames().find(deprecated_name);
   429→        if (it != deprecatedFactoryNames().end()) {
   430→          prev_deprecated_names.emplace_back(std::make_pair(it->first, it->second));
   431→          deprecatedFactoryNames().erase(it);
   432→
   433→          ENVOY_LOG(
   434→              info,
   435→              "Deprecated name '{}' (mapped to '{}') displaced with test factory '{}' (type '{}')",
   436→              it->first, it->second, factory.name(), factory.configTypes());
   437→        } else {
   438→          // Name not previously mapped, remember to remove it.
   439→          prev_deprecated_names.emplace_back(std::make_pair(deprecated_name, ""));
   440→
   441→          ENVOY_LOG(info, "Deprecated name '{}' (mapped to '{}')", deprecated_name, factory.name());
   442→        }
   443→
   444→        // Register the replacement factory with a deprecated name.
   445→        factories().emplace(deprecated_name, &factory);
   446→        RELEASE_ASSERT(getFactory(deprecated_name) == &factory,
   447→                       "test factory registration by deprecated name failed");
   448→
   449→        // Register the replacement factory's deprecated name.
   450→        deprecatedFactoryNames().emplace(std::make_pair(deprecated_name, factory.name()));
   451→      }
   452→    }
   453→
   454→    rebuildFactoriesByTypeForTest();
   455→
   456→    return [replacement = &factory, prev_by_name, prev_deprecated_names]() {
   457→      // Unregister the replacement factory by name.
   458→      factories().erase(replacement->name());
   459→
   460→      ENVOY_LOG(info, "Removed test factory '{}' (type '{}')", replacement->name(),
   461→                replacement->configTypes());
   462→
   463→      if (prev_by_name) {
   464→        // Restore any factory displaced by name, but only register the type if it's non-empty.
   465→        factories().emplace(prev_by_name->name(), prev_by_name);
   466→
   467→        ENVOY_LOG(info, "Restored factory '{}' (type '{}'), formerly displaced-by-name",
   468→                  prev_by_name->name(), prev_by_name->configTypes());
   469→      }
   470→
   471→      for (auto [prev_deprecated_name, mapped_canonical_name] : prev_deprecated_names) {
   472→        deprecatedFactoryNames().erase(prev_deprecated_name);
   473→
   474→        ENVOY_LOG(info, "Removed deprecated name '{}'", prev_deprecated_name);
   475→
   476→        if (!mapped_canonical_name.empty()) {
   477→          deprecatedFactoryNames().emplace(
   478→              std::make_pair(prev_deprecated_name, mapped_canonical_name));
   479→
   480→          auto* deprecated_factory = getFactory(mapped_canonical_name);
   481→          RELEASE_ASSERT(deprecated_factory != nullptr,
   482→                         "failed to restore deprecated factory name");
   483→          factories().emplace(mapped_canonical_name, deprecated_factory);
   484→
   485→          ENVOY_LOG(info, "Restored deprecated name '{}' (mapped to '{}'", prev_deprecated_name,
   486→                    mapped_canonical_name);
   487→        }
   488→      }
   489→
   490→      rebuildFactoriesByTypeForTest();
   491→    };
   492→  }
   493→};
   494→
   495→/**
   496→ * Factory registration template. Enables users to register a particular implementation factory with
   497→ * the FactoryRegistry by instantiating this templated class with the specific factory class and the
   498→ * general Base class to which that factory conforms.
   499→ *
   500→ * Because factories are generally registered once and live for the length of the program, the
   501→ * standard use of this class is static instantiation within a linked implementation's translation
   502→ * unit. For an example of a typical use case, @see NamedNetworkFilterConfigFactory.
   503→ *
   504→ * Example registration: REGISTER_FACTORY(SpecificFactory, BaseFactory);
   505→ *                       LEGACY_REGISTER_FACTORY(SpecificFactory, BaseFactory, "deprecated_name");
   506→ */
   507→template <class T, class Base> class RegisterFactory {
   508→public:
   509→  /**
   510→   * Constructor that registers an instance of the factory with the FactoryRegistry.
   511→   */
   512→  RegisterFactory() {
   513→    ASSERT(!instance_.name().empty());
   514→    FactoryRegistry<Base>::registerFactory(instance_, instance_.name());
   515→
   516→    // Also register this factory with its category.
   517→    //
   518→    // Each time a factory registers, the registry will attempt to
   519→    // register its category here. This means that we have to ignore
   520→    // multiple attempts to register the same category and can't detect
   521→    // duplicate categories.
   522→    if (!FactoryCategoryRegistry::isRegistered(instance_.category())) {
   523→      FactoryCategoryRegistry::registerCategory(instance_.category(),
   524→                                                new FactoryRegistryProxyImpl<Base>());
   525→    }
   526→  }
   527→
   528→  /**
   529→   * Constructor that registers an instance of the factory with the FactoryRegistry along with
   530→   * deprecated names.
   531→   */
   532→  explicit RegisterFactory(std::initializer_list<absl::string_view> deprecated_names) {
   533→    if (!instance_.name().empty()) {
   534→      FactoryRegistry<Base>::registerFactory(instance_, instance_.name());
   535→    } else {
   536→      ASSERT(deprecated_names.size() != 0,
   537→             "Attempted to register a factory without a name or deprecated name");
   538→    }
   539→
   540→    for (auto deprecated_name : deprecated_names) {
   541→      ASSERT(!deprecated_name.empty());
   542→      FactoryRegistry<Base>::registerFactory(instance_, deprecated_name, instance_.name());
   543→    }
   544→
   545→    if (!FactoryCategoryRegistry::isRegistered(instance_.category())) {
   546→      FactoryCategoryRegistry::registerCategory(instance_.category(),
   547→                                                new FactoryRegistryProxyImpl<Base>());
   548→    }
   549→  }
   550→
   551→  /**
   552→   * Constructor that registers an instance of the factory with the FactoryRegistry along with
   553→   * vendor specific version.
   554→   */
   555→  RegisterFactory(uint32_t major, uint32_t minor, uint32_t patch,
   556→                  const std::map<std::string, std::string>& version_metadata)
   557→      : RegisterFactory(major, minor, patch, version_metadata, {}) {}
   558→
   559→  /**
   560→   * Constructor that registers an instance of the factory with the FactoryRegistry along with
   561→   * vendor specific version and deprecated names.
   562→   */
   563→  RegisterFactory(uint32_t major, uint32_t minor, uint32_t patch,
   564→                  const std::map<std::string, std::string>& version_metadata,
   565→                  std::initializer_list<absl::string_view> deprecated_names) {
   566→    auto version = makeBuildVersion(major, minor, patch, version_metadata);
   567→    if (instance_.name().empty()) {
   568→      ASSERT(deprecated_names.size() != 0);
   569→    } else {
   570→      FactoryRegistry<Base>::registerFactory(instance_, instance_.name(), version);
   571→    }
   572→
   573→    for (auto deprecated_name : deprecated_names) {
   574→      ASSERT(!deprecated_name.empty());
   575→      FactoryRegistry<Base>::registerFactory(instance_, deprecated_name, version, instance_.name());
   576→    }
   577→
   578→    if (!FactoryCategoryRegistry::isRegistered(instance_.category())) {
   579→      FactoryCategoryRegistry::registerCategory(instance_.category(),
   580→                                                new FactoryRegistryProxyImpl<Base>());
   581→    }
   582→  }
   583→
   584→private:
   585→  static envoy::config::core::v3::BuildVersion
   586→  makeBuildVersion(uint32_t major, uint32_t minor, uint32_t patch,
   587→                   const std::map<std::string, std::string>& metadata) {
   588→    envoy::config::core::v3::BuildVersion version;
   589→    version.mutable_version()->set_major_number(major);
   590→    version.mutable_version()->set_minor_number(minor);
   591→    version.mutable_version()->set_patch(patch);
   592→    *version.mutable_metadata() = MessageUtil::keyValueStruct(metadata);
   593→    return version;
   594→  }
   595→
   596→  T instance_{};
   597→};
   598→
   599→/**
   600→ * RegisterInternalFactory is a special case for registering factories
   601→ * that are considered internal implementation details that should
   602→ * not be exposed to operators via the factory categories.
   603→ *
   604→ * There is no corresponding REGISTER_INTERNAL_FACTORY because
   605→ * this should be used sparingly and only in special cases.
   606→ */
   607→template <class T, class Base> class RegisterInternalFactory {
   608→public:
   609→  RegisterInternalFactory() {
   610→    ASSERT(!instance_.name().empty());
   611→    FactoryRegistry<Base>::registerFactory(instance_, instance_.name());
   612→  }
   613→
   614→private:
   615→  T instance_{};
   616→};
   617→
   618→#ifdef ENVOY_STATIC_EXTENSION_REGISTRATION
   619→/**
   620→ * Macro used for static registration.
   621→ */
   622→#define REGISTER_FACTORY(FACTORY, BASE)                                                            \
   623→  ABSL_ATTRIBUTE_UNUSED void forceRegister##FACTORY() {}                                           \
   624→  static Envoy::Registry::RegisterFactory</* NOLINT(fuchsia-statically-constructed-objects) */     \
   625→                                          FACTORY, BASE>                                           \
   626→      FACTORY##_registered
   627→/**
   628→ * Macro used for static registration with deprecated name.
   629→ */
   630→#define LEGACY_REGISTER_FACTORY(FACTORY, BASE, DEPRECATED_NAME)                                    \
   631→  ABSL_ATTRIBUTE_UNUSED void forceRegister##FACTORY() {}                                           \
   632→  static Envoy::Registry::RegisterFactory</* NOLINT(fuchsia-statically-constructed-objects) */     \
   633→                                          FACTORY, BASE>                                           \
   634→      FACTORY##_registered {                                                                       \
   635→    DEPRECATED_NAME                                                                                \
   636→  }
   637→#else
   638→/**
   639→ * Macro used to define a registration function.
   640→ */
   641→#define REGISTER_FACTORY(FACTORY, BASE)                                                            \
   642→  ABSL_ATTRIBUTE_UNUSED void forceRegister##FACTORY() {                                            \
   643→    ABSL_ATTRIBUTE_UNUSED static auto registered =                                                 \
   644→        new Envoy::Registry::RegisterFactory<FACTORY, BASE>();                                     \
   645→  }
   646→/**
   647→ * Macro used to define a registration function with deprecated name.
   648→ */
   649→#define LEGACY_REGISTER_FACTORY(FACTORY, BASE, DEPRECATED_NAME)                                    \
   650→  ABSL_ATTRIBUTE_UNUSED void forceRegister##FACTORY() {                                            \
   651→    ABSL_ATTRIBUTE_UNUSED static auto registered =                                                 \
   652→        new Envoy::Registry::RegisterFactory<FACTORY, BASE>({DEPRECATED_NAME});                    \
   653→  }
   654→#endif
   655→
   656→#define FACTORY_VERSION(major, minor, patch, ...) major, minor, patch, __VA_ARGS__
   657→
   658→/**
   659→ * Macro used for static registration declaration.
   660→ * Calling forceRegister...(); can be used to force the static factory initializer to run in a
   661→ * setting in which Envoy is bundled as a static archive. In this case, the static initializer is
   662→ * not run until a function in the compilation unit is invoked. The force function can be invoked
   663→ * from a static library wrapper.
   664→ */
   665→#define DECLARE_FACTORY(FACTORY) ABSL_ATTRIBUTE_UNUSED void forceRegister##FACTORY()
   666→
   667→} // namespace Registry
   668→} // namespace Envoy
